module top_module(out, in0, in1, obf_select);parameter bits = 32;	
output [bits-1:0] out;
input [bits-1:0] in0, in1;
input obf_select;

	reg [bits-1:0] out;

	always @ (obf_select or in0 or in1)
	case (obf_select)	
		0: out = in0;
		1: out = in1;

		default: out = 65'bx ;

	endcase
endmodule
